<script type="text/javascript" src="../assets/bootstrap/js/bootstrap.bundle.min.js"></script>
<script type="text/javascript" src="../assets/js/app.js"></script>

<script>
    const box = document.querySelector('.t_chat');
    box.scrollTop = box.scrollHeight;

    function fileUploader() {
        return {
            files: [],
            dragover: false,
            allowedTypes: [
                // Изображения
                'image/jpeg',
                'image/jpg',
                'image/png',

                // Документы
                'application/pdf'
            ],
            maxSize: 10 * 1024 * 1024, // 20 MB

            handleDrop(e) {
                this.dragover = false;
                this.addFiles(e.dataTransfer.files);
                this.uploadAll()
            },

            previewFiles(e) {
                this.addFiles(e.target.files);
                e.target.value = "";
            },

            addFiles(fileList) {
                for (let file of fileList) {
                    let error = null;

                    // проверка типа
                    if (!this.allowedTypes.includes(file.type)) {
                        error = "Недопустимый формат";
                    }

                    // проверка размера
                    if (file.size > this.maxSize) {
                        error = "Файл превышает 20 МБ";
                    }

                    this.files.push({
                        file,
                        name: file.name,
                        size: file.size,
                        type: file.type,
                        url: error ? null : (file.type.startsWith('image/') ? URL.createObjectURL(file) : null),
                        progress: 0,
                        error
                    });
                }
            },

            removeFile(index) {
                if (this.files[index].url) {
                    URL.revokeObjectURL(this.files[index].url);
                }
                this.files.splice(index, 1);
            },

            async uploadAll() {
                for (let f of this.files) {
                    if (!f.error) {
                        await this.fakeUpload(f);
                    }
                }
            },

            fakeUpload(file) {
                return new Promise(resolve => {
                    file.progress = 0;
                    let interval = setInterval(() => {
                        if (file.progress >= 100) {
                            clearInterval(interval);
                            resolve();
                        } else {
                            file.progress += 15;
                        }
                    }, 200);
                });
            },

            formatSize(size) {
                if (size < 1024) return size + ' B';
                else if (size < 1024 * 1024) return (size / 1024).toFixed(1) + ' KB';
                else return (size / (1024 * 1024)).toFixed(1) + ' MB';
            }
        }
    }
</script>


<script type="text/javascript" src="../assets/js/alpinejs.min.js"></script>


</body>
